<?php
// config/helper.php

// Function to format Rupiah
function formatRupiah($angka) {
    return "Rp " . number_format($angka, 0, ',', '.');
}

// Function to format date (e.g. 24 May 2026)
function formatTanggal($tanggal) {
    if (!$tanggal || $tanggal == '0000-00-00 00:00:00' || $tanggal == '0000-00-00') return '-';
    $waktu = strtotime($tanggal);
    $hari = date('d', $waktu);
    $bulan = date('m', $waktu);
    $tahun = date('Y', $waktu);
    $jam = date('H:i', $waktu);
    
    $namaBulan = array(
        '01' => 'Jan', '02' => 'Feb', '03' => 'Mar', '04' => 'Apr',
        '05' => 'Mei', '06' => 'Jun', '07' => 'Jul', '08' => 'Agt',
        '09' => 'Sep', '10' => 'Okt', '11' => 'Nov', '12' => 'Des'
    );
    
    if (strlen($tanggal) > 10) {
        return "$hari {$namaBulan[$bulan]} $tahun $jam";
    }
    return "$hari {$namaBulan[$bulan]} $tahun";
}

// Function to generate status badge HTML
function badgeStatus($status) {
    $labels = ['antrean' => 'Antrean', 'proses' => 'Proses', 'selesai' => 'Selesai', 'diambil' => 'Diambil'];
    $colors = ['antrean' => '#f43f5e', 'proses' => '#f59e0b', 'selesai' => '#10b981', 'diambil' => '#94a3b8'];
    
    $label = isset($labels[$status]) ? $labels[$status] : $status;
    $color = isset($colors[$status]) ? $colors[$status] : '#94a3b8';
    
    $dot = '<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background-color:'.$color.';margin-right:4px;"></span>';
    
    return "<span class=\"badge badge-$status\">$dot $label</span>";
}

// Function to generate payment badge HTML
function badgeBayar($status) {
    if ($status === 'lunas') {
        return '<span class="badge badge-lunas" style="display:inline-flex;align-items:center;gap:4px;">'.getIcon('banknotes', 'w-4 h-4').' Lunas</span>';
    }
    return '<span class="badge badge-belum" style="display:inline-flex;align-items:center;gap:4px;">'.getIcon('clock', 'w-4 h-4').' Belum Bayar</span>';
}

// Function to sanitize input
function sanitize($koneksi, $input) {
    return mysqli_real_escape_string($koneksi, trim($input));
}

// Function to redirect with message
function redirect($url, $message = null, $type = 'success') {
    if ($message) {
        $_SESSION['flash_msg'] = $message;
        $_SESSION['flash_type'] = $type;
    }
    header("Location: $url");
    exit;
}

// Function to check authentication and return user data
function requireAuth() {
    if (!isset($_SESSION['user_id'])) {
        header("Location: ../auth/login.php");
        exit;
    }
    return [
        'id' => $_SESSION['user_id'],
        'username' => $_SESSION['username'],
        'nama_lengkap' => $_SESSION['nama_lengkap'],
        'role' => $_SESSION['role']
    ];
}

function requireAdmin() {
    $user = requireAuth();
    if ($user['role'] !== 'admin') {
        die("Akses Ditolak: Fitur ini hanya untuk Administrator.");
    }
    return $user;
}

